INSERT INTO jobs (job_name, industry, city, company_type, salary_min, salary_max, skills, soft_skills, is_fresh_friendly, friendly_level, jd_content, core_duties, education, major, experience, post_type, bonus_skills, salary_range, post_time, apply_deadline, jd_link, post_category, party_label) VALUES ('培训经理 - 南昌（社招）', '互联网 / IT', '南昌', '民营企业', 10000, 15000, '1. 可独立完成培训体系搭建、课程开发、项目全流程执行与效果评估；2. 熟练使用Office办公软件，可完成课件制作、数据复盘与报告输出；3. 具备内部讲师团队建设、激励体系搭建能力', '1. 具备优秀的项目统筹与落地能力，目标导向；2. 具备良好的跨部门沟通协调能力，可联动业务部门推动培训成果落地；3. 学习能力强，具备创新思维，适配年轻化团队特性', 0, '一般', '1. 培训体系搭建：结合公司战略，搭建并迭代培训体系，制定年度/季度培训规划与预算方案；2. 课程开发与优化：主导核心课程开发，沉淀内部案例与知识资产；整合外部优质培训资源，适配业务快速迭代需求；3. 培训项目落地：统筹各类培训项目的全流程执行，包括需求调研、方案设计、组织实施、效果评估（柯氏四级评估）与复盘优化；4. 内训师团队建设：挖掘并培养内部业务骨干、管理层成为内训师，搭建内训师选拔、赋能、激励体系，提升内训师授课能力与课程质量；5. 培训效果转化：建立培训效果跟踪机制，联动业务部门推动培训成果落地，通过技能考核、业绩关联、行为改变等维度验证培训价值，助力员工成长与业务增长；6. 学习氛围营造：策划各类学习活动，搭建内部学习交流平台，推动学习型组织建设，契合新媒体行业年轻化团队特性', 'OD 组织发展支持', '大专及以上', '人力资源管理、工商管理、教育学等相关专业优先', '3年以上培训相关工作经验，有新媒体、互联网、营销类行业培训经验者优先，熟悉300人左右规模企业培训体系搭建逻辑', '社招（应届生可投）', '有新媒体/互联网营销行业培训经验；有300人以上规模企业培训体系搭建经验', '10k-15k/月', '46112', NULL, 'BOSS直聘平台获取', 'OD类', '甲方（企业自有 HR 岗）'), ('培训经理 - 厦门（社招）', '快消', '厦门', '民营企业', 7000, 11000, '1. 可独立建立和完善培训体系，开发标准化培训课程；2. 熟练使用Office办公软件，可完成课件、短视频、手册等培训物料制作；3. 具备培训考核机制搭建与效果落地能力', '1. 具备优秀的表达能力和课程开发能力，台风稳健；2. 热爱陶瓷文化和美食文化，学习能力强；3. 工作认真负责，具备良好的项目落地能力', 0, '一般', '1. 负责建立和完善加盟商及门店员工的培训体系；2. 开发标准化培训课程：白瓷文化知识、产品知识、销售技巧、服务礼仪、陈列技巧、咖啡/茶饮制作标准；3. 负责组织和实施各类培训活动：集中培训、线上培训、到店带教；4. 建立培训考核机制，确保培训效果落地；5. 配合米其林内容中心，将培训内容转化为短视频、手册等素材', 'OD 组织发展支持', '大专及以上', '无强制专业限制', '3年以上培训经验，有连锁零售、餐饮或消费品行业培训经验者优先', '社招（应届生可投）', '有连锁零售/餐饮/消费品行业培训经验；有短视频制作、课程物料开发经验', '7k-11k/月', '46112', NULL, 'BOSS直聘平台获取', 'OD类', '甲方（企业自有 HR 岗）'), ('培训经理 - 通辽（社招）', '其他', '通辽', '民营企业', 4000, 9000, '1. 具备优秀的课程开发与教学设计能力，能够独立完成培训材料的编写；2. 熟练使用Office办公软件，可完成课件制作、培训档案建立与数据整理；3. 熟悉咨询业务流程，具备培训效果跟踪与优化能力', '1. 沟通能力强，能够有效协调内外部资源，推动培训项目的顺利进行；2. 具有较强的分析判断能力和问题解决能力，能够根据培训反馈及时调整策略；3. 工作认真负责，目标导向，具备良好的项目管理能力', 0, '一般', '1. 负责设计和实施针对法律咨询团队的专业培训计划，提升团队整体业务能力；2. 根据公司